195: type RoleGetter struct {
196: 	Lister rbaclisters.RoleLister
197: }
198: 
199: func (g *RoleGetter) GetRole(ctx context.Context, namespace, name string) (*rbacv1.Role, error) {
200: 	return g.Lister.Roles(namespace).Get(name)
201: }
