28: // NewAuthorizer returns an authorizer which accepts a given set of paths.
29: // Each path is either a fully matching path or it ends in * in case a prefix match is done. A leading / is optional.
30: func NewAuthorizer(alwaysAllowPaths []string) (authorizer.Authorizer, error) {
31: 	var prefixes []string
32: 	paths := sets.NewString()
33: 	for _, p := range alwaysAllowPaths {
34: 		p = strings.TrimPrefix(p, "/")
35: 		if len(p) == 0 {
36: 			// matches "/"
37: 			paths.Insert(p)
38: 			continue
39: 		}
40: 		if strings.ContainsRune(p[:len(p)-1], '*') {
41: 			return nil, fmt.Errorf("only trailing * allowed in %q", p)
42: 		}
43: 		if strings.HasSuffix(p, "*") {
44: 			prefixes = append(prefixes, p[:len(p)-1])
45: 		} else {
46: 			paths.Insert(p)
47: 		}
48: 	}
49: 
50: 	return authorizer.AuthorizerFunc(func(ctx context.Context, a authorizer.Attributes) (authorizer.Decision, string, error) {
51: 		if a.IsResourceRequest() {
52: 			return authorizer.DecisionNoOpinion, "", nil
53: 		}
54: 
55: 		pth := strings.TrimPrefix(a.GetPath(), "/")
56: 		if paths.Has(pth) {
57: 			return authorizer.DecisionAllow, "", nil
58: 		}
59: 
60: 		for _, prefix := range prefixes {
61: 			if strings.HasPrefix(pth, prefix) {
62: 				return authorizer.DecisionAllow, "", nil
63: 			}
64: 		}
65: 
66: 		return authorizer.DecisionNoOpinion, "", nil
67: 	}), nil
68: }
